Below is a conceptual example in C++ using a hypothetical game engine API:

cpp
#include <iostream>
#include "GameEngine.h"

bool isCrossPlatformCompatible(const GameEngine& engine) {
    // Check if the engine supports cross-platform play
    return engine.supportsCrossPlay() && 
           engine.hasCrossSaveSupport() &&
           engine.isOnlineMultiplayerEnabled();
}

int main() {
    GameEngine myEngine("MyGame");
    if (isCrossPlatformCompatible(myEngine)) {
        std::cout << "Cross-platform play is supported." << std::endl;
    } else {
        std::cout << "Cross-platform play is not supported." << std::endl;
    }
    return 0;
}

This function checks if the game engine supports cross-platform multiplayer, cross-save functionality, and online multiplayer features.
